{
  "mode": "method",
  "tests": [
    {
      "name": "custom_option_class_present",
      "input": {
        "css_files": ["style1.css", "style2.css"],
        "html": "<span class='custom-option'>Option 1</span>"
      },
      "output": true,
      "notes": "Validates that the custom-option class is present in the loaded CSS files."
    },
    {
      "name": "custom_option_class_absent",
      "input": {
        "css_files": ["style1.css", "style2.css"],
        "html": "<span class='custom-option'>Option 1</span>"
      },
      "output": false,
      "notes": "Checks that the absence of custom-option in CSS files results in incorrect rendering."
    },
    {
      "name": "dropdown_rendering",
      "input": {
        "css_files": ["style1.css", "style2.css"],
        "html": "<select class='dropdown'><option>Yes</option><option>No</option></select>"
      },
      "output": "Yes/No dropdown appears",
      "notes": "Ensures that the dropdown renders correctly when CSS is applied."
    },
    {
      "name": "no_css_files",
      "input": {
        "css_files": [],
        "html": "<span class='custom-option'>Option 1</span>"
      },
      "output": false,
      "notes": "Tests the scenario where no CSS files are loaded, expecting failure."
    },
    {
      "name": "valid_css_file",
      "input": {
        "css_files": ["valid_style.css"],
        "html": "<span class='custom-option'>Option 1</span>"
      },
      "output": true,
      "notes": "Checks that a valid CSS file allows the dropdown to render correctly."
    },
    {
      "name": "invalid_css_file",
      "input": {
        "css_files": ["invalid_style.css"],
        "html": "<span class='custom-option'>Option 1</span>"
      },
      "output": false,
      "notes": "Validates that an invalid CSS file prevents the dropdown from rendering."
    },
    {
      "name": "multiple_options",
      "input": {
        "css_files": ["style1.css", "style2.css"],
        "html": "<select class='dropdown'><option>Yes</option><option>No</option><option>Maybe</option></select>"
      },
      "output": "Yes/No/Maybe dropdown appears",
      "notes": "Tests rendering of multiple options in the dropdown."
    },
    {
      "name": "empty_option",
      "input": {
        "css_files": ["style1.css", "style2.css"],
        "html": "<select class='dropdown'><option></option></select>"
      },
      "output": "Empty option appears",
      "notes": "Checks that an empty option is handled correctly."
    }
  ],
  "assumptions": "The custom-option class must be defined in at least one of the loaded CSS files for proper rendering.",
  "notes": "Ensure that the testing environment mimics the production setup as closely as possible."
}
